class Solution:
    def minOperations(self, s):
        n = len(s)
        # small strings: true brute-force BFS over every reachable string via <= 3 substring
        # sorts (any substring except the whole string), independent of the closed-form solution.
        if n <= 10:
            target = ''.join(sorted(s))
            if s == target:
                return 0
            if n == 2:
                return -1
            seen = {s}
            frontier = [s]
            depth = 0
            while depth < 3:
                depth += 1
                nxt = []
                for cur in frontier:
                    for l in range(n):
                        for r in range(l + 1, n):
                            if l == 0 and r == n - 1:
                                continue
                            cand = cur[:l] + ''.join(sorted(cur[l:r+1])) + cur[r+1:]
                            if cand == target:
                                return depth
                            if cand not in seen:
                                seen.add(cand)
                                nxt.append(cand)
                frontier = nxt
            return -1
        # larger strings: an independently-styled linear pass (built around Python's own
        # prefix/suffix helpers instead of the manual while-loops the optimal solution uses)
        t = sorted(s)
        pairs = list(zip(s, t))
        if all(a == b for a, b in pairs):
            return 0
        first_bad = next(i for i, (a, b) in enumerate(pairs) if a != b)
        last_bad = n - 1 - next(i for i, (a, b) in enumerate(reversed(pairs)) if a != b)
        if first_bad != 0 or last_bad != n - 1:
            return 1
        if n == 2:
            return -1
        mn, mx = t[0], t[-1]
        if s.find(mn) < n - 1 or s.rfind(mx) > 0:
            return 2
        return 3

