class Solution:
    def minOperations(self, s):
        n = len(s)
        t = sorted(s)
        if list(s) == t:
            return 0
        l = 0
        while s[l] == t[l]:
            l += 1
        r = n - 1
        while s[r] == t[r]:
            r -= 1
        if not (l == 0 and r == n - 1):
            return 1
        if n == 2:
            return -1
        mn, mx = t[0], t[-1]
        mn_in_prefix = any(ch == mn for ch in s[:n-1])
        mx_in_suffix = any(ch == mx for ch in s[1:])
        if mn_in_prefix or mx_in_suffix:
            return 2
        return 3

