var minOperations = function(s) {
    const n = s.length;
    const t = s.split('').sort();
    let sorted = true;
    for (let i = 0; i < n; i++) if (s[i] !== t[i]) { sorted = false; break; }
    if (sorted) return 0;
    let l = 0;
    while (s[l] === t[l]) l++;
    let r = n - 1;
    while (s[r] === t[r]) r--;
    if (!(l === 0 && r === n - 1)) return 1;
    if (n === 2) return -1;
    const mn = t[0], mx = t[n - 1];
    let mnInPrefix = false;
    for (let i = 0; i < n - 1; i++) if (s[i] === mn) { mnInPrefix = true; break; }
    let mxInSuffix = false;
    for (let i = 1; i < n; i++) if (s[i] === mx) { mxInSuffix = true; break; }
    if (mnInPrefix || mxInSuffix) return 2;
    return 3;
};
